<template><div class="testing-dashboard"><h2>Testing Dashboard</h2><div class="stats"><div class="stat"><h3>{{ stats.total }}</h3><p>Tổng số test</p></div><div class="stat passed"><h3>{{ stats.passed }}</h3><p>Đã qua</p></div><div class="stat failed"><h3>{{ stats.failed }}</h3><p>Thất bại</p></div><div class="stat"><h3>{{ stats.coverage }}%</h3><p>Code coverage</p></div></div><button class="btn-primary" @click="runAllTests">Chạy tất cả test</button></div></template>